import pygame
import random
import sys

# 初始化
pygame.init()

# 游戏参数
GRID_SIZE = 20
CELL_SIZE = 30
GRID_WIDTH = 20
GRID_HEIGHT = 20
SCREEN_WIDTH = GRID_WIDTH * CELL_SIZE
SCREEN_HEIGHT = GRID_HEIGHT * CELL_SIZE

# 颜色
BLACK = (0, 0, 0)
WHITE = (200, 200, 200)
GREEN = (0, 200, 0)
RED = (200, 0, 0)
DARK_GREEN = (0, 150, 0)
GRAY = (50, 50, 50)

# 方向
UP = (0, -1)
DOWN = (0, 1)
LEFT = (-1, 0)
RIGHT = (1, 0)

screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
pygame.display.set_caption("贪吃蛇")
clock = pygame.time.Clock()
font = pygame.font.SysFont("simhei", 36)
small_font = pygame.font.SysFont("simhei", 20)

def draw_grid():
    for x in range(0, SCREEN_WIDTH, CELL_SIZE):
        pygame.draw.line(screen, GRAY, (x, 0), (x, SCREEN_HEIGHT))
    for y in range(0, SCREEN_HEIGHT, CELL_SIZE):
        pygame.draw.line(screen, GRAY, (0, y), (SCREEN_WIDTH, y))

def draw_snake(snake):
    for i, (x, y) in enumerate(snake):
        rect = pygame.Rect(x * CELL_SIZE + 2, y * CELL_SIZE + 2, CELL_SIZE - 4, CELL_SIZE - 4)
        color = GREEN if i == 0 else DARK_GREEN
        pygame.draw.rect(screen, color, rect)

def draw_food(food):
    cx = food[0] * CELL_SIZE + CELL_SIZE // 2
    cy = food[1] * CELL_SIZE + CELL_SIZE // 2
    pygame.draw.circle(screen, RED, (cx, cy), CELL_SIZE // 2 - 3)

def show_message(text, sub_text=""):
    screen.fill(BLACK)
    msg = font.render(text, True, WHITE)
    screen.blit(msg, (SCREEN_WIDTH // 2 - msg.get_width() // 2, SCREEN_HEIGHT // 2 - 60))
    if sub_text:
        sub = small_font.render(sub_text, True, WHITE)
        screen.blit(sub, (SCREEN_WIDTH // 2 - sub.get_width() // 2, SCREEN_HEIGHT // 2 + 10))
    pygame.display.flip()

def spawn_food(snake):
    while True:
        pos = (random.randint(0, GRID_WIDTH - 1), random.randint(0, GRID_HEIGHT - 1))
        if pos not in snake:
            return pos

def game_loop():
    snake = [(5, 10), (4, 10), (3, 10)]
    direction = RIGHT
    next_direction = RIGHT
    food = spawn_food(snake)
    score = 0
    speed = 10

    while True:
        # 事件处理
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                return False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_UP and direction != DOWN:
                    next_direction = UP
                elif event.key == pygame.K_DOWN and direction != UP:
                    next_direction = DOWN
                elif event.key == pygame.K_LEFT and direction != RIGHT:
                    next_direction = LEFT
                elif event.key == pygame.K_RIGHT and direction != LEFT:
                    next_direction = RIGHT
                elif event.key == pygame.K_ESCAPE:
                    return False

        direction = next_direction
        head = snake[0]
        new_head = (head[0] + direction[0], head[1] + direction[1])

        # 撞墙检测
        if new_head[0] < 0 or new_head[0] >= GRID_WIDTH or new_head[1] < 0 or new_head[1] >= GRID_HEIGHT:
            return show_game_over(score)

        # 撞自身检测
        if new_head in snake:
            return show_game_over(score)

        snake.insert(0, new_head)

        # 吃食物
        if new_head == food:
            score += 1
            food = spawn_food(snake)
            if score % 5 == 0:
                speed = min(speed + 2, 25)
        else:
            snake.pop()

        # 绘制
        screen.fill(BLACK)
        draw_grid()
        draw_snake(snake)
        draw_food(food)

        # 分数
        score_text = small_font.render(f"得分: {score}", True, WHITE)
        screen.blit(score_text, (5, 5))

        pygame.display.flip()
        clock.tick(speed)

    return True

def show_game_over(score):
    waiting = True
    while waiting:
        show_message(f"游戏结束！得分: {score}", "按 R 重新开始 / ESC 退出")
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                return False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_r:
                    return True
                if event.key == pygame.K_ESCAPE:
                    return False

def main():
    while True:
        show_message("贪吃蛇", "按任意键开始")
        waiting = True
        while waiting:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    pygame.quit()
                    sys.exit()
                if event.type == pygame.KEYDOWN:
                    waiting = False

        if not game_loop():
            break

    pygame.quit()
    sys.exit()

if __name__ == "__main__":
    main()
